import json
import os
import boto3

s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")

TABLE_NAME = os.environ.get("TABLE_NAME", "your-table-name")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "arn:aws:sns:us-east-1:123456789012:your-topic-name")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "https://sqs.us-east-1.amazonaws.com/123456789012/your-queue-name")
S3_BUCKET = os.environ.get("S3_BUCKET", "your-shared-bucket")

table = dynamodb.Table(TABLE_NAME)

def lambda_handler(event, context):
    item_id = event.get("id", "default-id")
    payload = event.get("payload", {"message": "hello from shared-role lambda"})

    table.put_item(Item={"id": item_id, "payload": payload})

    s3.put_object(
        Bucket=S3_BUCKET,
        Key=f"events/{item_id}.json",
        Body=json.dumps(payload).encode("utf-8"),
        ContentType="application/json",
    )

    sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject="Lambda Event Processed",
        Message=json.dumps({"id": item_id, "status": "processed"}),
    )

    sqs.send_message(
        QueueUrl=SQS_QUEUE_URL,
        MessageBody=json.dumps({"id": item_id, "payload": payload}),
    )

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Processed successfully",
                "id": item_id,
                "table": TABLE_NAME,
                "bucket": S3_BUCKET,
            }
        ),
    }